const pakistanOffset = 5; // Pakistan timezone UTC+5

// Get current time in Pakistan timezone
const nowUTC = new Date();
const nowPakistan = new Date(nowUTC.getTime() + (pakistanOffset * 60 * 60 * 1000));

for (let i = 0; i < items.length; i++) {
  const campaign = items[i].json;

  // Step 1: Get UTC time from database
  const utcTime = new Date(campaign.scheduled_at);

  // Step 2: UTC + 5 = user selected time
  const userSelectedTime = new Date(utcTime.getTime() + (pakistanOffset * 60 * 60 * 1000));

  // Step 3: 5 - tz = timezone difference
  const userTz = parseFloat(campaign.tz);
  const timezoneDifference = pakistanOffset - userTz;

  // Step 4: user selected time + timezone difference = time to match
  const pakistanTime = new Date(userSelectedTime.getTime() + (timezoneDifference * 60 * 60 * 1000));

  // Calculate time difference in minutes
  const timeDifferenceMinutes = Math.round((pakistanTime - nowPakistan) / (1000 * 60));

  // Should execute if time has passed but not more than 60 minutes ago
  const shouldExecute = timeDifferenceMinutes >= -60 && timeDifferenceMinutes <= 0;

  // Add new fields while preserving all original data
  items[i].json = {
